import java.util.*;
import java.util.stream.*;

public class Main {
    interface Operation { int apply(int left, int right); }
    static final class Add implements Operation { public int apply(int left, int right) { return left + right; } }
    static final class Multiply implements Operation { public int apply(int left, int right) { return left * right; } }

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        String kind = input.next(); int left = input.nextInt(), right = input.nextInt();
        Operation operation = kind.equals("add") ? new Add() : new Multiply();
        System.out.println(operation.apply(left, right));
    }
}
